const raw  = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;

if (!body.job_id)          throw new Error('Stage 2 missing: job_id');
if (!body.seedance_prompts || !Array.isArray(body.seedance_prompts) || body.seedance_prompts.length === 0)
  throw new Error('Stage 2 missing: seedance_prompts array');
if (!body.narration)       throw new Error('Stage 2 missing: narration');

const MAX = 6;
const prompts = body.seedance_prompts.slice(0, MAX);
const negs    = (body.negative_prompts || []).slice(0, MAX);
const scenes  = (body.scenes || []).slice(0, MAX).map((s, i) => ({ ...s, scene_number: i+1, start_sec: i*5, end_sec: (i+1)*5 }));

const wsKey = $env.WAVESPEED_API_KEY || '';
if (!wsKey) console.warn('WARNING: WAVESPEED_API_KEY not set — Seedance calls will fail');

console.log('Stage 2 START | job:', body.job_id, '| clips:', prompts.length, '| exercise:', body.exercise_name);

return [{ json: {
  ...body,
  seedance_prompts: prompts,
  negative_prompts: negs,
  scenes,
  num_clips:    prompts.length,
  clip_dur_sec: 5,
  ws_key:       wsKey
}}];

const https = require('https');
const data  = $input.first().json;
const wsKey = data.ws_key || $env.WAVESPEED_API_KEY;
const prompts = data.seedance_prompts || [];

if (!wsKey) throw new Error('WAVESPEED_API_KEY not set. Add in n8n Settings > Environment Variables.');

function apiPost(prompt) {
  return new Promise((resolve, reject) => {
    const buf = Buffer.from(JSON.stringify({ prompt, duration: 5, aspect_ratio: '9:16', seed: -1 }));
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path:     '/api/v3/bytedance/seedance-v1-lite-t2v-720p',
      method:   'POST',
      headers:  { 'Authorization': 'Bearer ' + wsKey, 'Content-Type': 'application/json', 'Content-Length': buf.length }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { reject(new Error('Bad JSON from Wavespeed')); } });
    });
    req.on('error', reject);
    req.write(buf);
    req.end();
  });
}

const results = await Promise.all(prompts.map(p => apiPost(p)));
const seedance_job_ids = [];

for (let i = 0; i < results.length; i++) {
  const r = results[i];
  if (!r.data || !r.data.id) throw new Error('Scene ' + (i+1) + ' submit failed: ' + JSON.stringify(r).slice(0,300));
  seedance_job_ids.push(r.data.id);
  console.log('[' + (i+1) + '/' + results.length + '] submitted -> ' + r.data.id);
}

console.log('All ' + seedance_job_ids.length + ' scenes submitted to Seedance. Polling starts in 30s...');
return [{ json: { ...data, seedance_job_ids, video_urls: new Array(prompts.length).fill(null), poll_attempt: 0, all_done: 0, submitted_at: Date.now() } }];

const https  = require('https');
const data   = $input.first().json;
const wsKey  = data.ws_key || $env.WAVESPEED_API_KEY;
const jobIds = data.seedance_job_ids || [];
const urls   = [...(data.video_urls || [])];
const attempt= (data.poll_attempt || 0) + 1;

if (!wsKey) throw new Error('WAVESPEED_API_KEY not set.');
console.log('━━━ Poll #' + attempt + ' (' + jobIds.length + ' clips) ━━━');

function apiGet(taskId) {
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path:     '/api/v3/predictions/' + taskId + '/result',
      method:   'GET',
      headers:  { 'Authorization': 'Bearer ' + wsKey }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { reject(new Error('Non-JSON from Wavespeed')); } });
    });
    req.on('error', reject);
    req.end();
  });
}

for (let i = 0; i < jobIds.length; i++) {
  if (urls[i] !== null) { console.log('  Scene '+(i+1)+' already done'); continue; }
  const r = await apiGet(jobIds[i]);
  const status = (r.data && r.data.status) || 'unknown';
  const pct    = r.data && r.data.progress != null ? ' (' + r.data.progress + '%)' : '';
  console.log('  Scene '+(i+1)+'/'+jobIds.length+' -> '+status+pct);
  if (status === 'completed') {
    const url = r.data.outputs && r.data.outputs[0];
    if (!url) throw new Error('Scene '+(i+1)+' completed but no output URL');
    urls[i] = url;
    console.log('    done: ' + url.split('?')[0].slice(-40));
  } else if (status === 'failed') {
    throw new Error('Scene '+(i+1)+' FAILED: ' + JSON.stringify(r.data));
  }
}

const done  = urls.filter(u => u !== null).length;
const total = jobIds.length;
const all_done = done === total ? 1 : 0;
console.log('Progress: '+done+'/'+total+' clips ready'+(all_done ? ' — ALL DONE!' : ' — waiting...'));

return [{ json: { ...data, video_urls: urls, poll_attempt: attempt, all_done } }];

const { execSync } = require('child_process');
const fs     = require('fs');
const data   = $input.first().json;
const jobId  = data.job_id;
const urls   = data.video_urls || [];
const n8nIn  = '/data/ffmpeg/input';
const contIn = '/ffmpeg/input';

if (!fs.existsSync(n8nIn)) fs.mkdirSync(n8nIn, { recursive: true });

const clipPaths = [];
for (let i = 0; i < urls.length; i++) {
  const name     = jobId + '_scene' + (i+1) + '.mp4';
  const n8nPath  = n8nIn  + '/' + name;
  const contPath = contIn + '/' + name;
  console.log('Downloading scene ' + (i+1) + ': ' + urls[i].split('?')[0].slice(-50));
  const cmd = 'docker exec qpc_ffmpeg_runner curl -sL -o "' + contPath + '" "' + urls[i] + '" && echo DL_OK';
  const res = execSync(cmd, { encoding: 'utf-8', timeout: 120000 });
  if (!res.includes('DL_OK')) throw new Error('Download failed for scene '+(i+1));
  if (!fs.existsSync(n8nPath)) throw new Error('File missing after download: '+n8nPath);
  clipPaths.push(n8nPath);
  console.log('  saved: ' + name);
}

console.log('All ' + clipPaths.length + ' clips downloaded.');
return [{ json: { ...data, clip_paths: clipPaths } }];
